// components/AutoReport.jsx — Rapport PDF automatique
import React, { useState, useCallback } from 'react';
import { LOGO_BASE64 } from '../assets/logo';

const API = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5001/api';

const TYPE_LABELS = {
  water_pollution: 'Pollution eau', air_pollution: 'Pollution air',
  soil_contamination: 'Contamination sol', waste_deposit: 'Dépôt déchets',
  dust: 'Poussière', noise_pollution: 'Pollution sonore', other: 'Autre',
};
const STATUS_LABELS = {
  new: 'Nouveau', verified: 'Vérifié', in_progress: 'En cours',
  resolved: 'Résolu', rejected: 'Rejeté',
};



const generatePDF = (data) => {
  const { period, generatedAt, stats, recentReports, topCitizens, byType, byRegion } = data;

  const periodLabel = { '7d': '7 derniers jours', '30d': '30 derniers jours', '90d': '90 derniers jours' }[period] || period;

  const typeRows = (byType || []).map(t =>
    `<tr><td style="padding:8px 12px">${TYPE_LABELS[t.type] || t.type}</td><td style="padding:8px 12px;text-align:right;font-weight:700">${t.count}</td></tr>`
  ).join('');

  const regionRows = (byRegion || []).map(r =>
    `<tr><td style="padding:8px 12px">📍 ${r.region}</td><td style="padding:8px 12px;text-align:right;font-weight:700">${r.count}</td></tr>`
  ).join('');

  const reportRows = (recentReports || []).slice(0, 15).map((r, i) => {
    const loc = r.location || {};
    const c = r.citizen && typeof r.citizen === 'object' ? r.citizen : {};
    return `<tr style="background:${i%2===0?'#fff':'#f9fafb'}">
      <td style="padding:7px 10px;font-size:11px;color:#6b7280;font-family:monospace">#${(r._id||'').slice(-8)}</td>
      <td style="padding:7px 10px;font-size:12px">${TYPE_LABELS[r.type] || r.type || ''}</td>
      <td style="padding:7px 10px;font-size:11px">${(r.description||'').substring(0,50)}</td>
      <td style="padding:7px 10px"><span style="padding:2px 8px;border-radius:10px;font-size:10px;font-weight:600;background:#f0fdf4;color:#166534">${STATUS_LABELS[r.status] || r.status || ''}</span></td>
      <td style="padding:7px 10px;font-size:11px;color:#6b7280">${loc.address||loc.city||''}</td>
      <td style="padding:7px 10px;font-size:11px">${((c.firstName||'') + ' ' + (c.lastName||'')).trim() || c.email || 'Anonyme'}</td>
    </tr>`;
  }).join('');

  const citizenRows = (topCitizens || []).map((c, i) =>
    `<tr><td style="padding:8px 12px">${['🥇','🥈','🥉','4️⃣','5️⃣'][i] || (i+1)}</td><td style="padding:8px 12px">${c.name || 'Anonyme'}</td><td style="padding:8px 12px;text-align:right;font-weight:700">${c.count}</td></tr>`
  ).join('');

  const resolutionRate = stats?.totalReports > 0
    ? Math.round((stats.resolvedReports / stats.totalReports) * 100)
    : 0;

  const html = `<!DOCTYPE html><html><head><meta charset="utf-8">
<title>ReMine — Rapport ${periodLabel}</title>
<style>
  * { margin:0; padding:0; box-sizing:border-box; }
  body { font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif; color:#111; }
  .header { background:linear-gradient(135deg,#16a34a,#0f5132); color:#fff; padding:36px 48px; }
  .logo { display:flex; align-items:center; gap:12px; margin-bottom:20px; }
  .logo h1 { font-size:28px; font-weight:900; }
  .logo p { font-size:13px; opacity:.7; }
  .header-meta { font-size:13px; opacity:.8; margin-bottom:20px; }
  .kpis { display:grid; grid-template-columns:repeat(4,1fr); gap:14px; }
  .kpi { background:rgba(255,255,255,.15); border-radius:12px; padding:14px 18px; }
  .kpi .val { font-size:28px; font-weight:900; }
  .kpi .lbl { font-size:10px; opacity:.8; text-transform:uppercase; letter-spacing:.5px; margin-top:2px; }
  .body { padding:36px 48px; }
  .section { margin-bottom:32px; }
  .section-title { font-size:16px; font-weight:800; color:#111; margin-bottom:14px; display:flex; align-items:center; gap:8px; border-bottom:2px solid #e5e7eb; padding-bottom:8px; }
  .grid2 { display:grid; grid-template-columns:1fr 1fr; gap:20px; }
  table { width:100%; border-collapse:collapse; border-radius:10px; overflow:hidden; }
  th { padding:10px 12px; text-align:left; font-size:10px; font-weight:700; color:#6b7280; text-transform:uppercase; letter-spacing:.5px; background:#f8fafc; border-bottom:2px solid #e5e7eb; }
  tr { border-bottom:1px solid #f0f0f0; }
  .footer { margin-top:32px; padding-top:16px; border-top:2px solid #e5e7eb; display:flex; justify-content:space-between; color:#9ca3af; font-size:11px; }
  @media print { body { -webkit-print-color-adjust:exact; print-color-adjust:exact; } }
</style></head><body>

<div class="header">
  <div class="logo">
    <img src="data:image/png;base64," alt="ReMine" style="width:48px;height:48px;object-fit:contain;flex-shrink:0;" />
    <div><h1>ReMine</h1><p>Citizen Track — Rapport Automatique</p></div>
  </div>
  <p class="header-meta">📅 Période : <strong>${periodLabel}</strong> · Généré le ${new Date(generatedAt).toLocaleDateString('fr-FR', { weekday:'long', year:'numeric', month:'long', day:'numeric' })}</p>
  <div class="kpis">
    <div class="kpi"><div class="val">${stats?.totalReports || 0}</div><div class="lbl">Total signalements</div></div>
    <div class="kpi"><div class="val">${stats?.activeReports || 0}</div><div class="lbl">Signalements actifs</div></div>
    <div class="kpi"><div class="val">${stats?.resolvedReports || 0}</div><div class="lbl">Résolus</div></div>
    <div class="kpi"><div class="val">${resolutionRate}%</div><div class="lbl">Taux résolution</div></div>
  </div>
</div>

<div class="body">
  <div class="grid2">
    <!-- Types -->
    <div class="section">
      <div class="section-title">📊 Répartition par type</div>
      <table><thead><tr><th>Type de pollution</th><th style="text-align:right">Nb.</th></tr></thead>
      <tbody>${typeRows || '<tr><td colspan="2" style="padding:12px;color:#9ca3af;text-align:center">Aucune donnée</td></tr>'}</tbody></table>
    </div>
    <!-- Régions -->
    <div class="section">
      <div class="section-title">📍 Top zones d'intervention</div>
      <table><thead><tr><th>Région</th><th style="text-align:right">Nb.</th></tr></thead>
      <tbody>${regionRows || '<tr><td colspan="2" style="padding:12px;color:#9ca3af;text-align:center">Aucune donnée</td></tr>'}</tbody></table>
    </div>
  </div>

  <!-- Signalements récents -->
  <div class="section">
    <div class="section-title">📋 Signalements de la période (${(recentReports||[]).length})</div>
    <table><thead><tr><th>ID</th><th>Type</th><th>Description</th><th>Statut</th><th>Localisation</th><th>Citoyen</th></tr></thead>
    <tbody>${reportRows || '<tr><td colspan="6" style="padding:12px;color:#9ca3af;text-align:center">Aucun signalement sur cette période</td></tr>'}</tbody></table>
  </div>

  <!-- Top citoyens -->
  ${citizenRows ? `<div class="section">
    <div class="section-title">🏆 Top citoyens contributeurs</div>
    <table><thead><tr><th>Rang</th><th>Citoyen</th><th style="text-align:right">Signalements</th></tr></thead>
    <tbody>${citizenRows}</tbody></table>
  </div>` : ''}

  <div class="footer">
    <span>ReMine Citizen Track — Rapport confidentiel</span>
    <span>Généré le ${new Date().toLocaleString('fr-FR')}</span>
  </div>
</div>
</body></html>`;

  const win = window.open('', '_blank');
  if (win) {
    win.document.write(html);
    win.document.close();
    setTimeout(() => win.print(), 700);
  }
};

export const AutoReport = () => {
  const [period, setPeriod]   = useState('7d');
  const [loading, setLoading] = useState(false);
  const [lastGen, setLastGen] = useState(null);
  const [preview, setPreview] = useState(null);

  const handleGenerate = useCallback(async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('remine_admin_token');
      const res = await fetch(`${API}/admin/report-data?period=${period}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      if (data.success) {
        setPreview(data.data);
        setLastGen(new Date());
        generatePDF(data.data);
      }
    } catch (e) {
      console.error('Erreur génération rapport:', e);
    } finally {
      setLoading(false);
    }
  }, [period]);

  const periodLabel = { '7d': '7 derniers jours', '30d': '30 derniers jours', '90d': '90 derniers jours' }[period];

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
        <div className="flex items-center gap-3 mb-5">
          <img src={LOGO_BASE64} alt="ReMine" className="w-10 h-10 object-contain flex-shrink-0" />
          <div>
            <h2 className="text-lg font-bold text-gray-900">Rapport automatique</h2>
            <p className="text-xs text-gray-400">Générez un rapport PDF complet sur l'activité de la plateforme</p>
          </div>
        </div>

        {/* Sélecteur de période */}
        <div className="mb-5">
          <p className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">Période du rapport</p>
          <div className="flex gap-3 flex-wrap">
            {[
              { key: '7d',  label: '7 derniers jours',  icon: '📅' },
              { key: '30d', label: '30 derniers jours', icon: '📆' },
              { key: '90d', label: '90 derniers jours', icon: '🗓️' },
            ].map(p => (
              <button key={p.key} onClick={() => setPeriod(p.key)}
                      className={`flex items-center gap-2 px-4 py-3 rounded-xl text-sm font-semibold transition-all border-2 ${
                        period === p.key
                          ? 'border-red-500 bg-red-50 text-red-700 shadow-sm'
                          : 'border-gray-200 bg-white text-gray-600 hover:border-gray-300'
                      }`}>
                <span>{p.icon}</span>
                {p.label}
              </button>
            ))}
          </div>
        </div>

        {/* Contenu du rapport */}
        <div className="bg-gray-50 rounded-xl p-4 mb-5">
          <p className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">Le rapport inclut</p>
          <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
            {[
              '📊 KPIs principaux',
              '📋 Signalements de la période',
              '🗺️ Répartition par zone',
              '📈 Distribution par type',
              '🏆 Top citoyens contributeurs',
              '✅ Taux de résolution',
            ].map(item => (
              <div key={item} className="flex items-center gap-2 text-xs text-gray-600 bg-white rounded-lg px-3 py-2">
                <span className="text-green-500">✓</span> {item}
              </div>
            ))}
          </div>
        </div>

        {/* Bouton génération */}
        <div className="flex items-center gap-3">
          <button onClick={handleGenerate} disabled={loading}
                  className="flex items-center gap-3 px-6 py-3 rounded-xl font-semibold text-white transition-all disabled:opacity-50 shadow-sm"
                  style={{ background: loading ? '#9ca3af' : 'linear-gradient(135deg, #dc2626, #b91c1c)' }}>
            {loading ? (
              <><span className="animate-spin inline-block">⟳</span> Génération en cours…</>
            ) : (
              <><span>📄</span> Générer le rapport PDF — {periodLabel}</>
            )}
          </button>
          {lastGen && (
            <p className="text-xs text-gray-400">
              Dernier rapport : {lastGen.toLocaleTimeString('fr-FR')}
            </p>
          )}
        </div>
      </div>

      {/* Aperçu des données */}
      {preview && (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
          <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
            <span className="w-6 h-6 bg-gray-100 rounded-lg flex items-center justify-center text-sm">👁️</span>
            Aperçu — {periodLabel}
          </h3>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-5">
            {[
              { label: 'Signalements',  value: preview.recentReports?.length || 0, color: '#16a34a' },
              { label: 'Résolus',       value: preview.stats?.resolvedReports || 0, color: '#16a34a' },
              { label: 'Actifs',        value: preview.stats?.activeReports || 0,   color: '#f59e0b' },
              { label: 'Taux résol.',   value: `${Math.round((preview.stats?.resolutionRate || 0))}%`, color: '#3b82f6' },
            ].map(s => (
              <div key={s.label} className="bg-gray-50 rounded-xl p-4 text-center">
                <p className="text-2xl font-black" style={{ color: s.color }}>{s.value}</p>
                <p className="text-xs text-gray-500 mt-1">{s.label}</p>
              </div>
            ))}
          </div>

          {/* Top types */}
          {preview.byType?.length > 0 && (
            <div>
              <p className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Types les plus signalés</p>
              <div className="flex flex-wrap gap-2">
                {preview.byType.slice(0, 5).map(t => (
                  <span key={t.type} className="flex items-center gap-1.5 bg-emerald-50 text-emerald-700 text-xs font-semibold px-3 py-1.5 rounded-full">
                    {TYPE_LABELS[t.type] || t.type} <span className="bg-emerald-200 px-1.5 rounded-full">{t.count}</span>
                  </span>
                ))}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};